#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long d = Y - X;
        long long ans;
        if(d == 0) ans = 0;
        else if(d > 0){
            if(d & 1LL) ans = 1; // odd
            else if(d % 4 == 2) ans = 2;
            else ans = 3; // multiple of 4
        } else { // d < 0
            long long nd = -d;
            if((nd & 1LL) == 0) ans = 1; // even
            else ans = 2; // odd
        }
        printf("%lld\n", ans);
    }
    return 0;
}

