            long ans;
            if(d == 0) ans = 0;
            else if(d > 0){
                if((d & 1L) == 1L) ans = 1; // odd
                else if(d % 4 == 2) ans = 2;
                else ans = 3; // multiple of 4
            } else {
                long nd = -d;
                if((nd & 1L) == 0L) ans = 1; // even
                else ans = 2; // odd
            }
